import math


class Calculator:
    def __init__(self, epsilon=1e-9):
        self.epsilon = epsilon

    def compute(self, x):
        # BUG: no check for x<=0 before sqrt/log
        return math.sqrt(x) + math.log(x)

    def batch(self, nums):
        return [self.compute(n) for n in nums]


def compute(x):
    return Calculator().compute(x)


def main():
    nums = [4, 9, -1, 16]
    results = [compute(n) for n in nums]
    print(results)


if __name__ == '__main__':
    main()
